1	import { quote, claim, type Item, type Incident } from "./claim-office.js";
2	
3	export type QuoteStep = {
4	  op: "quote";
5	  items: Item[];
6	};
7	
8	export type ClaimStep = {
9	  op: "claim";
10	  policy: number;
11	  incident: Incident;
12	};
13	
14	export type ScenarioStep = QuoteStep | ClaimStep;
15	
16	export type Scenario = {
17	  customer: { yearsWithMHPCO: number };
18	  steps: ScenarioStep[];
19	};
20	
21	export type StepResult = {
22	  premium?: number;
23	  payout?: number;
24	  remainingCap?: number;
25	};
26	
27	export type ScenarioResult = {
28	  results: StepResult[];
29	};
30	
31	const isQuoteStep = (step: ScenarioStep): step is QuoteStep => step.op === "quote";
32	
33	const runQuoteStep = (
34	  step: QuoteStep,
35	  priorSteps: ScenarioStep[],
36	  yearsWithMHPCO: number
37	): StepResult => {
38	  const isFollowUp = priorSteps.some(isQuoteStep);
39	  return { premium: quote(step.items, { yearsWithMHPCO, isFollowUp }) };
40	};
41	
42	const runClaimStep = (
43	  step: ClaimStep,
44	  steps: ScenarioStep[],
45	  remainingCaps: Map<number, number>
46	): StepResult => {
47	  const policyStep = steps[step.policy];
48	  if (!isQuoteStep(policyStep)) {
49	    throw new Error(`Claim policy index ${step.policy} does not reference a quote step`);
50	  }
51	  const priorCap = remainingCaps.get(step.policy);
52	  const result =
53	    priorCap === undefined
54	      ? claim(policyStep.items, step.incident)
55	      : claim(policyStep.items, step.incident, priorCap);
56	  remainingCaps.set(step.policy, result.remainingCap);
57	  return result;
58	};
59	
60	export function runScenario(scenario: Scenario): ScenarioResult {
61	  const { yearsWithMHPCO } = scenario.customer;
62	  const { steps } = scenario;
63	  const remainingCaps = new Map<number, number>();
64	  const results = steps.map((step, index): StepResult =>
65	    isQuoteStep(step)
66	      ? runQuoteStep(step, steps.slice(0, index), yearsWithMHPCO)
67	      : runClaimStep(step, steps, remainingCaps)
68	  );
69	  return { results };
70	}
